import React, { useEffect, useState } from 'react';

function ShoppingPage() {
  const [links, setLinks] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    fetch("http://127.0.0.1:5000/shopping-links")
      .then((res) => res.json())
      .then((data) => {
        if (data.links) {
          setLinks(data.links);
        } else {
          setError("No shopping links found.");
        }
      })
      .catch((err) => {
        console.error("Error fetching shopping links:", err);
        setError("Failed to load shopping links.");
      });
  }, []);

  return (
    <div className="page-container">
      <h2>Costume Shopping Links</h2>
      {error && <p className="error-message">{error}</p>}
      <div className="shopping-grid">
        {links.map((item, index) => (
          <div key={index} className="shopping-card">
            <img src={item.image} alt={item.name} />
            <h4>{item.name}</h4>
            <p>{item.price}</p>
            <a href={item.url} target="_blank" rel="noopener noreferrer">
              Buy Now
            </a>
          </div>
        ))}
      </div>
    </div>
  );
}

export default ShoppingPage;
